import SwiftUI
import UIKit

struct PromoData: Equatable {
    let code: String
    let discount: Int
}

final class UserAccountStore: ObservableObject {
    @Published private(set) var appliedPromo: PromoData?
    @Published private(set) var statusMessage: String = "No promo applied"

    func applyPromo(code: String, discount: Int) {
        let sanitizedCode = code.trimmingCharacters(in: .whitespacesAndNewlines)
        let sanitizedDiscount = max(0, min(discount, 100))

        guard !sanitizedCode.isEmpty else {
            statusMessage = "Invalid promo code"
            return
        }

        let promo = PromoData(code: sanitizedCode, discount: sanitizedDiscount)
        appliedPromo = promo
        statusMessage = "Applied promo \(promo.code) for \(promo.discount)% off"
    }
}

final class PromoLinkHandler {
    static let shared = PromoLinkHandler()

    private init() {}

    func handle(url: URL, accountStore: UserAccountStore) -> Bool {
        guard isValidPromoURL(url) else { return false }
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else { return false }

        let queryItems = components.queryItems ?? []
        let code = queryItems.first(where: { $0.name.caseInsensitiveCompare("code") == .orderedSame })?.value
        let discountString = queryItems.first(where: { $0.name.caseInsensitiveCompare("discount") == .orderedSame })?.value

        guard let code, !code.isEmpty else { return false }
        guard let discountString, let discount = Int(discountString) else { return false }

        accountStore.applyPromo(code: code, discount: discount)
        return true
    }

    private func isValidPromoURL(_ url: URL) -> Bool {
        guard let scheme = url.scheme?.lowercased(),
              let host = url.host?.lowercased() else {
            return false
        }

        let normalizedPath = url.path.trimmingCharacters(in: CharacterSet(charactersIn: "/")).lowercased()
        return (scheme == "https" || scheme == "http") && host == "myapp.com" && normalizedPath == "promo"
    }
}

final class AppDelegate: NSObject, UIApplicationDelegate {
    var accountStore: UserAccountStore?

    func application(_ application: UIApplication,
                     continue userActivity: NSUserActivity,
                     restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL,
              let accountStore = accountStore else {
            return false
        }

        return PromoLinkHandler.shared.handle(url: url, accountStore: accountStore)
    }
}

